    28→// List handles GET /projects/{projectId}/semantic-releases — returns a paginated list of semantic releases for a project.
    29→func (h *SemanticReleasesHandler) List(w http.ResponseWriter, r *http.Request) {
    30→	projectID := r.PathValue("projectId")
    31→	if projectID == "" {
    32→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    33→		return
    34→	}
    35→	page, perPage := ParsePagination(r)
    36→	releases, total, err := h.store.ListSemanticReleases(r.Context(), projectID, page, perPage)
    37→	if err != nil {
    38→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list semantic releases")
    39→		return
    40→	}
    41→	if releases == nil {
    42→		releases = []models.SemanticRelease{}
    43→	}
    44→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    45→}
    46→
    47→// Get handles GET /semantic-releases/{id} — returns a single semantic release.
    48→func (h *SemanticReleasesHandler) Get(w http.ResponseWriter, r *http.Request) {
    49→	id := r.PathValue("id")
    50→	if id == "" {
    51→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Semantic release ID is required")
    52→		return
    53→	}
    54→	sr, err := h.store.GetSemanticRelease(r.Context(), id)
    55→	if err != nil {
    56→		RespondError(w, r, http.StatusNotFound, "not_found", "Semantic release not found")
    57→		return
    58→	}
    59→	RespondJSON(w, r, http.StatusOK, sr)
    60→}
    61→
    62→// Delete handles DELETE /semantic-releases/{id} — deletes a single semantic release.
    63→func (h *SemanticReleasesHandler) Delete(w http.ResponseWriter, r *http.Request) {
    64→	id := r.PathValue("id")
    65→	if id == "" {
    66→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Semantic release ID is required")
    67→		return
    68→	}
    69→	if err := h.store.DeleteSemanticRelease(r.Context(), id); err != nil {
    70→		RespondError(w, r, http.StatusNotFound, "not_found", "Semantic release not found")
    71→		return
    72→	}
    73→	w.WriteHeader(http.StatusNoContent)
    74→}
