   731→// CreateSemanticRelease inserts a semantic release and its source release links
   732→// in a single transaction. The sr.ID field is populated on success.
   733→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   734→	tx, err := s.pool.Begin(ctx)
   735→	if err != nil {
   736→		return fmt.Errorf("begin tx: %w", err)
   737→	}
   738→	defer tx.Rollback(ctx)
   739→
   740→	err = tx.QueryRow(ctx,
   741→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   742→		 VALUES ($1, $2, $3, $4, $5)
   743→		 RETURNING id, created_at`,
   744→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   745→	).Scan(&sr.ID, &sr.CreatedAt)
   746→	if err != nil {
   747→		return fmt.Errorf("insert semantic release: %w", err)
   748→	}
   749→
   750→	for _, relID := range releaseIDs {
   751→		_, err = tx.Exec(ctx,
   752→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   753→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   754→			sr.ID, relID,
   755→		)
   756→		if err != nil {
   757→			return fmt.Errorf("insert semantic release source: %w", err)
   758→		}
   759→	}
   760→
   761→	return tx.Commit(ctx)
   762→}
