   764→// UpdateAgentRunResult sets the semantic_release_id for a completed agent run.
   765→func (s *PgStore) UpdateAgentRunResult(ctx context.Context, id string, semanticReleaseID string) error {
   766→	tag, err := s.pool.Exec(ctx,
   767→		`UPDATE agent_runs SET semantic_release_id = $1 WHERE id = $2`,
   768→		semanticReleaseID, id,
   769→	)
   770→	if err != nil {
   771→		return fmt.Errorf("update agent run result: %w", err)
   772→	}
   773→	if tag.RowsAffected() == 0 {
   774→		return fmt.Errorf("agent run not found: %s", id)
   775→	}
   776→	return nil
   777→}
