   779→// ListProjectSubscriptions returns all project-level subscriptions for a given project.
   780→func (s *PgStore) ListProjectSubscriptions(ctx context.Context, projectID string) ([]models.Subscription, error) {
   781→	rows, err := s.pool.Query(ctx,
   782→		`SELECT id, channel_id, type, source_id, project_id, COALESCE(version_filter,''), created_at
   783→		 FROM subscriptions
   784→		 WHERE type = 'project' AND project_id = $1`, projectID)
   785→	if err != nil {
   786→		return nil, fmt.Errorf("list project subscriptions: %w", err)
   787→	}
   788→	defer rows.Close()
   789→	var subs []models.Subscription
   790→	for rows.Next() {
   791→		var sub models.Subscription
   792→		if err := rows.Scan(&sub.ID, &sub.ChannelID, &sub.Type, &sub.SourceID,
   793→			&sub.ProjectID, &sub.VersionFilter, &sub.CreatedAt); err != nil {
   794→			return nil, fmt.Errorf("scan subscription: %w", err)
   795→		}
   796→		subs = append(subs, sub)
   797→	}
   798→	return subs, nil
   799→}
