   811→func (s *PgStore) GetStats(ctx context.Context) (*DashboardStats, error) {
   812→	var stats DashboardStats
   813→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM releases`).Scan(&stats.TotalReleases); err != nil {
   814→		return nil, fmt.Errorf("count releases: %w", err)
   815→	}
   816→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM sources WHERE enabled = true`).Scan(&stats.ActiveSources); err != nil {
   817→		return nil, fmt.Errorf("count active sources: %w", err)
   818→	}
   819→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM projects`).Scan(&stats.TotalProjects); err != nil {
   820→		return nil, fmt.Errorf("count projects: %w", err)
   821→	}
   822→	if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM agent_runs WHERE status = 'pending'`).Scan(&stats.PendingAgentRuns); err != nil {
   823→		return nil, fmt.Errorf("count pending agent runs: %w", err)
   824→	}
   825→	return &stats, nil
   826→}
