	}
	page, perPage := ParsePagination(r)
	releases, total, err := h.store.ListReleasesBySource(r.Context(), sourceID, page, perPage)
	if err != nil {
		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
