     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { useState, useRef, useEffect, useCallback } from "react";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→  contextSources as ctxApi,
    11→  semanticReleases as srApi,
    12→  agent as agentApi,
    13→} from "@/lib/api/client";
    14→import type { AgentRules, Source } from "@/lib/api/types";
    15→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    16→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    17→import { SourceForm } from "@/components/sources/source-form";
    18→import { NewContextSourceForm } from "@/components/context-sources/new-context-source-form";
    19→import { ProviderBadge } from "@/components/ui/provider-badge";
    20→import { StatusDot } from "@/components/ui/status-dot";
    21→import { VersionChip } from "@/components/ui/version-chip";
    22→import { SectionLabel } from "@/components/ui/section-label";
    23→import { Pencil, Trash2, Play, Plus } from "lucide-react";
    24→
    25→/* ---------- Tabs ---------- */
    26→
    27→const tabs = [
    28→  { key: "sources", label: "Sources" },
    29→  { key: "context", label: "Context Sources" },
    30→  { key: "semantic", label: "Semantic Releases" },
    31→  { key: "agent", label: "Agent" },
    32→] as const;
    33→
    34→type TabKey = (typeof tabs)[number]["key"];
    35→
    36→/* ---------- Helpers ---------- */
    37→
    38→function formatDuration(startedAt?: string, completedAt?: string): string {
    39→  if (!startedAt) return "--";
    40→  const start = new Date(startedAt).getTime();
    41→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    42→  const secs = Math.round((end - start) / 1000);
    43→  if (secs < 60) return `${secs}s`;
    44→  const mins = Math.floor(secs / 60);
    45→  const rem = secs % 60;
    46→  return `${mins}m ${rem}s`;
    47→}
    48→
    49→function truncate(str: string, max: number): string {
    50→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    51→}
    52→
    53→function formatInterval(seconds: number): string {
    54→  if (seconds < 60) return `${seconds}s`;
    55→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    56→  return `${(seconds / 3600).toFixed(1)}h`;
    57→}
    58→
    59→/* ---------- Urgency chip ---------- */
    60→
    61→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    62→  critical: { bg: "#dc2626", text: "#ffffff" },
    63→  high: { bg: "#f97316", text: "#ffffff" },
    64→};
    65→
    66→function UrgencyChip({ urgency }: { urgency: string }) {
    67→  const u = urgency.toLowerCase();
    68→  const style = URGENCY_COLORS[u];
    69→  if (!style) return null;
    70→  return (
    71→    <span
    72→      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    73→      style={{ backgroundColor: style.bg, color: style.text }}
    74→    >
    75→      {urgency}
    76→    </span>
    77→  );
    78→}
    79→
    80→/* ---------- Main component ---------- */
    81→
    82→export function ProjectDetail({ id }: { id: string }) {
    83→  const router = useRouter();
    84→  const [activeTab, setActiveTab] = useState<TabKey>("sources");
    85→  const [triggering, setTriggering] = useState(false);
    86→
    87→  /* Agent config local state */
    88→  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    89→  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    90→  const [saving, setSaving] = useState(false);
    91→
    92→  /* Inline edit state */
    93→  const [editingName, setEditingName] = useState(false);
    94→  const [editingDesc, setEditingDesc] = useState(false);
    95→  const [nameDraft, setNameDraft] = useState("");
    96→  const [descDraft, setDescDraft] = useState("");
    97→  const nameRef = useRef<HTMLInputElement>(null);
    98→  const descRef = useRef<HTMLInputElement>(null);
    99→
   100→  /* Dialog state */
   101→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
   102→  const [editingSource, setEditingSource] = useState<Source | null>(null);
   103→  const [deletingSourceId, setDeletingSourceId] = useState<string | null>(null);
   104→  const [ctxCreateOpen, setCtxCreateOpen] = useState(false);
   105→  const [deletingCtxId, setDeletingCtxId] = useState<string | null>(null);
   106→  const [deletingProject, setDeletingProject] = useState(false);
   107→
   108→  /* Data fetching */
   109→  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
   110→  const { data: sourcesData, mutate: mutateSources } = useSWR(
   111→    activeTab === "sources" ? `project-${id}-sources` : null,
   112→    () => sourcesApi.listByProject(id),
   113→  );
   114→  const { data: ctxData, mutate: mutateCtx } = useSWR(
   115→    activeTab === "context" ? `project-${id}-ctx` : null,
   116→    () => ctxApi.list(id),
   117→  );
   118→  const { data: srData } = useSWR(
   119→    activeTab === "semantic" ? `project-${id}-sr` : null,
   120→    () => srApi.list(id),
   121→  );
   122→  const { data: runsData, mutate: mutateRuns } = useSWR(
   123→    activeTab === "agent" ? `project-${id}-runs` : null,
   124→    () => agentApi.listRuns(id),
   125→  );
   126→
   127→  const saveName = useCallback(async () => {
   128→    const p = data?.data;
   129→    if (!p) return;
   130→    const trimmed = nameDraft.trim();
   131→    if (trimmed && trimmed !== p.name) {
   132→      await projectsApi.update(id, { name: trimmed, description: p.description });
   133→      mutateProject();
   134→    }
   135→    setEditingName(false);
   136→  }, [nameDraft, data, id, mutateProject]);
   137→
   138→  const saveDesc = useCallback(async () => {
   139→    const p = data?.data;
   140→    if (!p) return;
   141→    const trimmed = descDraft.trim();
   142→    if (trimmed !== (p.description ?? "")) {
   143→      await projectsApi.update(id, { name: p.name, description: trimmed || undefined });
   144→      mutateProject();
   145→    }
   146→    setEditingDesc(false);
   147→  }, [descDraft, data, id, mutateProject]);
   148→
   149→  /* Click-outside handlers */
   150→  useEffect(() => {
   151→    if (!editingName) return;
   152→    const handler = (e: MouseEvent) => {
   153→      if (nameRef.current && !nameRef.current.contains(e.target as Node)) saveName();
   154→    };
   155→    document.addEventListener("mousedown", handler);
   156→    return () => document.removeEventListener("mousedown", handler);
   157→  }, [editingName, saveName]);
   158→
   159→  useEffect(() => {
   160→    if (!editingDesc) return;
   161→    const handler = (e: MouseEvent) => {
   162→      if (descRef.current && !descRef.current.contains(e.target as Node)) saveDesc();
   163→    };
   164→    document.addEventListener("mousedown", handler);
   165→    return () => document.removeEventListener("mousedown", handler);
   166→  }, [editingDesc, saveDesc]);
   167→
   168→  /* Handlers */
   169→  const handleTriggerRun = async () => {
   170→    setTriggering(true);
   171→    try {
   172→      await agentApi.triggerRun(id);
   173→      mutateRuns();
   174→    } finally {
   175→      setTriggering(false);
   176→    }
   177→  };
   178→
   179→  const handleToggleSource = async (source: { id: string; provider: string; repository: string; poll_interval_seconds: number; enabled: boolean; config?: Record<string, unknown> }) => {
   180→    await sourcesApi.update(source.id, {
   181→      provider: source.provider,
   182→      repository: source.repository,
   183→      poll_interval_seconds: source.poll_interval_seconds,
   184→      enabled: !source.enabled,
   185→      config: source.config,
   186→    });
   187→    mutateSources();
   188→  };
   189→
   190→  const handleSaveAgentConfig = async () => {
   191→    if (!project) return;
   192→    setSaving(true);
   193→    try {
   194→      const input = {
   195→        name: project.name,
   196→        description: project.description,
   197→        agent_prompt: promptDraft ?? project.agent_prompt,
   198→        agent_rules: rulesDraft ?? project.agent_rules,
   199→      };
   200→      await projectsApi.update(id, input);
   201→      mutateProject();
   202→      setPromptDraft(null);
   203→      setRulesDraft(null);
   204→    } finally {
   205→      setSaving(false);
   206→    }
   207→  };
   208→
   209→  /* Loading / not found states */
   210→  if (isLoading) {
   211→    return (
   212→      <div className="flex h-48 items-center justify-center" style={{ color: "#9ca3af" }}>
   213→        Loading...
   214→      </div>
   215→    );
   216→  }
   217→
   218→  const project = data?.data;
   219→  if (!project) {
   220→    return (
   221→      <div className="flex h-48 items-center justify-center" style={{ color: "#6b7280" }}>
   222→        Project not found
   223→      </div>
   224→    );
   225→  }
   226→
   227→  /* Derived counts */
   228→  const sourceCount = sourcesData?.data?.length;
   229→  const ctxCount = ctxData?.data?.length;
   230→
   231→  /* Current effective values */
   232→  const currentPrompt = promptDraft ?? project.agent_prompt ?? "";
   233→  const currentRules: AgentRules = rulesDraft ?? project.agent_rules ?? {};
   234→
   235→  return (
   236→    <div className="space-y-0">
   237→      {/* ===== Header zone ===== */}
   238→      <div
   239→        className="-m-6 mb-0 border-b px-6 py-5"
   240→        style={{ backgroundColor: "#ffffff", borderColor: "#e8e8e5" }}
   241→      >
   242→        <div className="flex items-start justify-between">
   243→          {/* Left: project info */}
   244→          <div className="min-w-0 flex-1">
   245→            {editingName ? (
   246→              <input
   247→                ref={nameRef}
   248→                value={nameDraft}
   249→                onChange={(e) => setNameDraft(e.target.value)}
   250→                onKeyDown={(e) => {
   251→                  if (e.key === "Enter") saveName();
   252→                  if (e.key === "Escape") setEditingName(false);
   253→                }}
   254→                autoFocus
   255→                className="w-full max-w-md rounded-md border px-2 py-1 text-[28px] font-bold leading-tight focus:outline-none focus:ring-1"
   256→                style={{
   257→                  fontFamily: "var(--font-fraunces), serif",
   258→                  borderColor: "#e8e8e5",
   259→                  color: "#111113",
   260→                }}
   261→              />
   262→            ) : (
   263→              <h1
   264→                className="group flex cursor-pointer items-center gap-2 text-[28px] font-bold leading-tight"
   265→                style={{ fontFamily: "var(--font-fraunces), serif" }}
   266→                onClick={() => {
   267→                  setNameDraft(project.name);
   268→                  setEditingName(true);
   269→                }}
   270→              >
   271→                {project.name}
   272→                <Pencil className="h-4 w-4 shrink-0 opacity-0 transition-opacity group-hover:opacity-40" />
   273→              </h1>
   274→            )}
   275→            {editingDesc ? (
   276→              <input
   277→                ref={descRef}
   278→                value={descDraft}
   279→                onChange={(e) => setDescDraft(e.target.value)}
   280→                onKeyDown={(e) => {
   281→                  if (e.key === "Enter") saveDesc();
   282→                  if (e.key === "Escape") setEditingDesc(false);
   283→                }}
   284→                autoFocus
   285→                placeholder="Add a description..."
   286→                className="mt-1 w-full max-w-lg rounded-md border px-2 py-1 text-[14px] focus:outline-none focus:ring-1"
   287→                style={{
   288→                  fontFamily: "var(--font-dm-sans), sans-serif",
   289→                  borderColor: "#e8e8e5",
   290→                  color: "#6b7280",
   291→                }}
   292→              />
   293→            ) : (
   294→              <p
   295→                className="group mt-1 flex cursor-pointer items-center gap-2 text-[14px]"
   296→                style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#6b7280" }}
   297→                onClick={() => {
   298→                  setDescDraft(project.description ?? "");
   299→                  setEditingDesc(true);
   300→                }}
   301→              >
   302→                {project.description || "Add a description..."}
   303→                <Pencil className="h-3 w-3 shrink-0 opacity-0 transition-opacity group-hover:opacity-40" />
   304→              </p>
   305→            )}
   306→            <p
   307→              className="mt-2 text-[12px]"
   308→              style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#9ca3af" }}
   309→            >
   310→              {sourceCount !== undefined ? `${sourceCount} sources` : "-- sources"}
   311→              {" \u00B7 "}
   312→              {ctxCount !== undefined ? `${ctxCount} context sources` : "-- context sources"}
   313→            </p>
   314→          </div>
   315→
   316→          {/* Right: actions */}
   317→          <div className="flex shrink-0 items-center gap-2 ml-4">
   318→            <button
   319→              onClick={() => setDeletingProject(true)}
   320→              className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-red-50"
   321→              style={{
   322→                fontFamily: "var(--font-dm-sans), sans-serif",
   323→                borderColor: "#dc2626",
   324→                color: "#dc2626",
   325→              }}
   326→            >
   327→              <Trash2 className="h-3.5 w-3.5" />
   328→              Delete
   329→            </button>
   330→            <button
   331→              onClick={handleTriggerRun}
   332→              disabled={triggering}
   333→              className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 text-[13px] font-medium text-white transition-colors disabled:opacity-60"
   334→              style={{
   335→                fontFamily: "var(--font-dm-sans), sans-serif",
   336→                backgroundColor: "#e8601a",
   337→              }}
   338→            >
   339→              <Play className="h-3.5 w-3.5" />
   340→              {triggering ? "Running..." : "Run Agent"}
   341→            </button>
   342→          </div>
   343→        </div>
   344→      </div>
   345→
   346→      {/* ===== Tab bar ===== */}
   347→      <div
   348→        className="-mx-6 border-b px-6"
   349→        style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   350→      >
   351→        <div className="flex gap-0">
   352→          {tabs.map((tab) => {
   353→            const isActive = activeTab === tab.key;
   354→            return (
   355→              <button
   356→                key={tab.key}
   357→                onClick={() => setActiveTab(tab.key)}
   358→                className="relative px-4 py-2.5 text-[13px] font-medium transition-colors"
   359→                style={{
   360→                  fontFamily: "var(--font-dm-sans), sans-serif",
   361→                  color: isActive ? "#111113" : "#9ca3af",
   362→                }}
   363→              >
   364→                {tab.label}
   365→                {isActive && (
   366→                  <span
   367→                    className="absolute bottom-0 left-4 right-4 h-[2px]"
   368→                    style={{ backgroundColor: "#e8601a" }}
   369→                  />
   370→                )}
   371→              </button>
   372→            );
   373→          })}
   374→        </div>
   375→      </div>
   376→
   377→      {/* ===== Tab content ===== */}
   378→      <div className="pt-6">
   379→        {/* --- Sources tab --- */}
   380→        {activeTab === "sources" && (
   381→          <div>
   382→            <div className="mb-4 flex items-center justify-between">
   383→              <SectionLabel>Sources</SectionLabel>
   384→              <button
   385→                onClick={() => setSourceCreateOpen(true)}
   386→                className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-[#f3f3f1]"
   387→                style={{
   388→                  fontFamily: "var(--font-dm-sans), sans-serif",
   389→                  borderColor: "#e8e8e5",
   390→                  color: "#374151",
   391→                }}
   392→              >
   393→                <Plus className="h-3.5 w-3.5" />
   394→                Add Source
   395→              </button>
   396→            </div>
   397→
   398→            {sourcesData?.data && sourcesData.data.length > 0 ? (
   399→              <div className="overflow-hidden rounded-md border" style={{ borderColor: "#e8e8e5" }}>
   400→                <table className="w-full text-[13px]" style={{ fontFamily: "var(--font-dm-sans), sans-serif" }}>
