   333→                          className="inline-flex items-center transition-colors hover:opacity-70"
   334→                          style={{ color: "#9ca3af" }}
   335→                          title="View on provider"
   336→                        >
   337→                          <ExternalLink size={14} />
   338→                        </a>
   339→                      ) : null;
   340→                    })()}
   341→                  </td>
   342→                </tr>
   343→              ))}
   344→            </tbody>
   345→          </table>
   346→        )}
   347→      </div>
   348→
   349→      {/* Pagination */}
   350→      {total > 0 && (
   351→        <div className="flex items-center justify-between">
   352→          <span
   353→            style={{
   354→              fontFamily: "var(--font-dm-sans)",
   355→              fontSize: "13px",
   356→              color: "#9ca3af",
   357→            }}
   358→          >
   359→            {startRow}&ndash;{endRow} of {total}
   360→          </span>
   361→          <div className="flex items-center gap-2">
   362→            <button
   363→              disabled={page <= 1}
   364→              onClick={() => setPage(page - 1)}
   365→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   366→              style={{
   367→                fontFamily: "var(--font-dm-sans)",
   368→                fontSize: "13px",
   369→                color: "#374151",
   370→                border: "1px solid #e8e8e5",
   371→              }}
   372→            >
   373→              Previous
   374→            </button>
   375→            <button
   376→              disabled={page >= totalPages}
   377→              onClick={() => setPage(page + 1)}
   378→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   379→              style={{
   380→                fontFamily: "var(--font-dm-sans)",
   381→                fontSize: "13px",
   382→                color: "#374151",
   383→                border: "1px solid #e8e8e5",
   384→              }}
   385→            >
   386→              Next
   387→            </button>
   388→          </div>
   389→        </div>
   390→      )}
   391→    </div>
   392→  );
   393→}
