### 3. **Status Badges & Urgency Chips**

**Type/Provider badges (channels):**
```tsx
const TYPE_STYLES: Record<string, { bg: string; text: string; icon?: IconType }> = {
  slack: { bg: "#4A154B", text: "#ffffff", icon: FaSlack },
  discord: { bg: "#5865F2", text: "#ffffff", icon: FaDiscord },
  webhook: { bg: "#1a1a1a", text: "#ffffff", icon: TbWebhook },
};

function TypeBadge({ type }: { type: string }) {
  const style = TYPE_STYLES[type.toLowerCase()];
  const colors = style ?? { bg: "#6b7280", text: "#ffffff" };
  const Icon = style?.icon;
  return (
    <span
      className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5"
      style={{
        backgroundColor: colors.bg,
        color: colors.text,
        fontFamily: "var(--font-dm-sans)",
        fontSize: "12px",
        fontWeight: 500,
        lineHeight: "16px",
      }}
    >
      {Icon && <Icon size={12} />}
      {type}
    </span>
  );
}
```

**Urgency chips (critical/high):**
```tsx
const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
  critical: { bg: "#dc2626", text: "#ffffff" },
  high: { bg: "#f97316", text: "#ffffff" },
};

// Usage
{urgencyStyle && (
  <span
    className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none"
    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
  >
    {sr.report!.urgency}
  </span>
)}
```

**Provider badges:**
```tsx
const PROVIDER_STYLES: Record<string, { bg: string; text: string; label: string; icon: IconType }> = {
  github: { bg: "#1a1a1a", text: "#ffffff", label: "GitHub", icon: FaGithub },
  dockerhub: { bg: "#2496ed", text: "#ffffff", label: "Docker Hub", icon: FaDocker },
};

export function ProviderBadge({ provider, className }: ProviderBadgeProps) {
  const style = PROVIDER_STYLES[provider.toLowerCase()];
  const resolved = style ?? { bg: "#6b7280", text: "#ffffff", label: provider };
  const Icon = style?.icon;
  return (
    <span
      className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
      style={{ backgroundColor: resolved.bg, color: resolved.text }}
    >
      {Icon && <Icon size={11} />}
      {resolved.label}
    </span>
  );
}
```

